UPDATE sites SET horario = 'Martes a viernes, 9:00 a. m.–5:00 p. m.; sábados, 10:00 a. m.–5:00 p. m. (cerrado domingos y lunes).', tarifa = 'Entrada libre y gratuita.', direccion = 'Carrera 7 #4-69, Área Cultural del Banco de la República, centro histórico (diagonal al Teatro Municipal).', datos_historicos = 'Inaugurado en 1991 como parte de la red de museos del oro del país. Inaugurado el 9 de mayo de 1991.' WHERE id = 's10';
UPDATE sites SET horario = 'Abierto en días de función; taquilla y venta en línea según cartelera.', tarifa = 'Boletería según evento.', direccion = 'Carrera 3 #12-28, centro.', datos_historicos = 'Abrió sus puertas en 1931. Estuvo cerrado y en ruinas durante años hasta su gloriosa restauración en los años 80, salvándolo de la demolición. Sala de 1.136 sillas en cuatro localidades.' WHERE id = 's22';
UPDATE sites SET horario = 'Jueves a domingo, 9:00 a. m.–3:00 p. m. (último ingreso hacia las 2:00 p. m.).', tarifa = 'Adultos (13+) $17.000; niños (2–12) $15.000; combo con el Zoológico $40.000 / $30.000. Boletas en las taquillas del Zoológico o en TuBoleta.', direccion = 'Oeste de Cali, sobre la cuenca del río Cali (contiguo al Zoológico de Cali), en terrenos de Celsia.', datos_historicos = 'Promovido por la Fundación Zoológica de Cali para expandir la conservación vegetal. Reabierto al público en septiembre de 2024; administrado por la Fundación Zoológico de Cali.' WHERE id = 's18';
UPDATE sites SET horario = 'Martes a domingo y festivos, 9:30 a. m.–4:30 p. m. (cerrado el martes siguiente a un lunes festivo).', tarifa = 'Adultos $18.000; niños $10.500; adultos mayores y PcD $9.000; extranjeros 10 USD (venta solo en taquilla).', direccion = 'Corregimiento de Santa Elena, El Cerrito (Valle), a ~36 km de Cali.', datos_historicos = 'Construida entre 1816 y 1828. Fue adquirida por el padre de Jorge Isaacs en 1854. Casa museo administrada por INCIVA; BIC de la Nación.' WHERE id = 's36';
UPDATE sites SET horario = 'Lunes a viernes, 9:00 a. m.–12:30 p. m. y 2:00–5:00 p. m.', tarifa = 'Visita libre al taller-tienda (los carteles y productos se venden aparte).', direccion = 'Carrera 5 #2-70, barrio San Antonio.', datos_historicos = 'Fundada en 1934. Fue salvada de la quiebra en 2017 gracias a la unión de sus trabajadores veteranos y diseñadores jóvenes. Funciona desde 1934; en San Antonio desde 1987.' WHERE id = 's43';
UPDATE sites SET horario = 'Lunes a viernes, 8:00 a. m.–6:00 p. m.; sábados, 3:00–6:00 p. m.; domingos, 10:00 a. m.–6:00 p. m.', tarifa = 'Entrada $20.000 (a modo de donación para su sostenimiento).', direccion = 'Avenida Belalcázar (Carrera 2 Oeste) #5A-55, oeste de Cali (junto al Gato de Tejada y el Museo La Tertulia).', datos_historicos = 'Fundado en 2008 por Hugo Suárez, un apasionado coleccionista. Fundado el 22 de octubre de 2008 por Hugo Suárez Fiat.' WHERE id = 's34';
UPDATE sites SET horario = 'Abierta al público en horarios de culto (misas).', tarifa = 'Entrada gratuita.', direccion = 'Carrera 1ª con Calle 13, a orillas del río Cali.', datos_historicos = 'La construcción actual se inició en 1930 y finalizó en 1942, reemplazando una capilla del siglo XVII. El templo neogótico actual se construyó en la primera mitad del siglo XX (décadas de 1930–1940), en reemplazo de la ermita colonial arruinada por los terremotos; su estilo se inspira en las catedrales góticas europeas.', datos_curiosos = ARRAY['Guarda la imagen del ''Señor de la Caña'', única sobreviviente del terremoto de 1787.', 'Su reloj musical suena cada hora, alegrando el centro.', 'Conserva la imagen colonial del Señor de la Caña (o Señor de los Milagros), sobreviviente de los sismos.']::text[] WHERE id = 's16';
UPDATE sites SET horario = 'Colina y parque abiertos todo el día; la capilla abre en horarios de misa.', tarifa = 'Gratuita.', datos_historicos = 'Construida en 1747 en honor a San Antonio de Padua. La capilla data de 1747 (construcción iniciada en 1746); es uno de los templos más antiguos de la ciudad (BIC).' WHERE id = 's63';
UPDATE sites SET horario = 'Parque abierto todo el día.', tarifa = 'Gratuita.', descripcion = 'Una deliciosa galería de arte a cielo abierto a orillas del río Cali. Presidida por el monumental ''Gato del Río'', una obra en bronce del maestro Hernando Tejada, esta zona verde se convirtió en el hogar de sus ''novias'': una colección de más de 15 gatas esculpidas e intervenidas pictóricamente por reconocidos artistas colombianos (como Maripaz Jaramillo, Omar Rayo, etc.). Cada gata tiene una personalidad, historia y diseño único. Es un paseo colorido, artístico y refrescante. El Gato del Río, de Hernando Tejada, se instaló el 3 de julio de 1996; ''Las Gatas del Río'' (esculturas intervenidas por distintos artistas) se sumaron en 2006.' WHERE id = 's8';
UPDATE sites SET horario = 'Abierto a diario, con más ambiente en la tarde-noche.', tarifa = 'Ingreso libre (las artesanías y la comida se pagan aparte).', descripcion = 'El corazón de la artesanía y la cultura bohemia en Cali. Este parque artesanal, construido arquitectónicamente en niveles sobre una colina, está lleno de casetas donde artesanos locales fabrican y venden joyas, trabajos en cuero, madera e instrumentos musicales. Pero más que un mercado, es un centro cultural vivo: los jueves son noches de narración oral (cuenteros), y los fines de semana hay danzas folclóricas y música andina en vivo. Un espacio de resistencia cultural. Se consolidó como parque y mercado artesanal en las últimas décadas del siglo XX; es punto de referencia del comercio artesanal caleño.' WHERE id = 's11';
UPDATE sites SET horario = 'Plaza pública, abierta.', tarifa = 'Libre.', descripcion = 'El kilómetro cero de Cali. Esta plaza, rodeada de palmeras altísimas ''Roystonea regia'', es el corazón cívico y comercial histórico de la ciudad. A su alrededor se erigen edificios emblemáticos de arquitectura republicana y neoclásica como la Catedral de San Pedro, el Palacio Nacional y el Edificio Otero. Es un lugar vibrante, lleno de vendedores de tinto, lustrabotas y transeúntes, donde se siente el pulso diario de la ciudad y se cruzan todas las historias. La antigua Plaza Mayor colonial (luego Plaza de la Constitución) fue rebautizada Plaza de Caycedo en 1813, en honor al prócer Joaquín de Caycedo y Cuero; el monumento central se erigió en 1913.' WHERE id = 's39';
UPDATE sites SET horario = 'Se recomienda el ascenso de madrugada o en la mañana (por seguridad y clima); funciona como ecoparque (Bataclán).', tarifa = 'Gratuita.', descripcion = 'El reto físico por excelencia de los caleños. Subir a las Tres Cruces es un ritual matutino de fin de semana para miles de personas. El sendero es empinado y exige esfuerzo físico, pero la recompensa es una vista inigualable de la ciudad y un jugo de naranja fresco en la cima. Las tres grandes cruces de concreto dominan el paisaje y protegen, según la leyenda, a la ciudad del demonio ''Buziraco''. Según la tradición, se erigió una cruz en el cerro para ''conjurar'' al diablo Buziraco; las tres cruces actuales, en concreto, datan de finales de los años treinta del siglo XX.' WHERE id = 's65';
UPDATE sites SET horario = 'Espacio público abierto.', tarifa = 'Libre.', descripcion = 'Es la ''sala de recibo'' moderna de Cali. Un extenso y ventilado paseo peatonal a orillas del río que transformó el centro de la ciudad. Aquí la brisa de la tarde es la protagonista. Es el lugar democrático donde convergen caleños de todas las edades y clases sociales para caminar, tomar un café, escuchar música espontánea o simplemente ver pasar la vida. Conecta la arquitectura histórica del Puente Ortiz y la Ermita con la modernidad del centro administrativo. Inaugurado en 2013, tras peatonalizar el antiguo tramo de la Avenida Colombia a orillas del río Cali.' WHERE id = 's3';
UPDATE sites SET horario = 'Abierto; zona de baño en el río y senderos (mayor afluencia los fines de semana).', tarifa = 'Ingreso libre (algunos servicios y parqueaderos privados aparte).', descripcion = 'Si quieres saber qué hace un caleño auténtico el domingo, ve a Pance. Este río de aguas frías y cristalinas que baja directamente de los Farallones es el balneario natural y democrático de la ciudad. El ecoparque ofrece senderos para caminar, zonas de picnic, lagos y acceso directo al río. Es un ritual sagrado sumergirse en sus aguas para ''sacarse el calor'' y luego disfrutar de un sancocho de gallina en leña en los restaurantes aledaños. El río Pance nace en el Parque Nacional Natural Farallones de Cali; su ribera se consolidó como zona de recreación y ecoparque de la ciudad.' WHERE id = 's20';